var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"루루는 좀 어때?","JPN":"ルルはどう？","ENG":"How's Lulu?","TWN":"露露還好嗎？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아직도 자. 많이 피곤했나 봐.","JPN":"まだ寝てる。めっちゃ疲れてたみたい。","ENG":"Still sleeping. She must've been bone-tired.","TWN":"她還在睡，看來是很累的樣子。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"피곤할 만하지. 그렇게 큰 힘을 썼으니…….","JPN":"疲れるわけだよ。あんなに力を使ったんだから……","ENG":"Sounds about right. I mean, she did use a lot of her powers...","TWN":"一定很累吧，花那麼大的力氣……"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"피로가 풀릴 때까지 우리가 데리고 있을 테니까 걱정 마.","JPN":"疲れが取れるまで私たちが見てるから、心配しないで。","ENG":"We'll take care of her until she's fully rested. So don't worry.","TWN":"放心吧，在她醒來之前，我們會照顧好她。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너희는 이 난리를 어떻게 책임질지나 생각해.","JPN":"あんたたちはこの騒動の責任をどうやって取るか考えておいて。","ENG":"You girls should think of how you're going to take responsibility for all of this.","TWN":"你們想想要如何收拾這場騷動！"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"오히려 잘 된 거 아냐? 원래 관리국에서 하려던 일을 우리가 대신 해 준 거잖아.","JPN":"むしろよかったんじゃない？　もともと管理局でしようとしてたことを私たちが代わりにやってあげたんだからさ。","ENG":"But it turned out fine, didn't it? Like, we did the Administration's work for them.","TWN":"這樣不是正好嗎？管理局不是原本就打算這麼做嗎？我們只是代勞而已。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아직도 정신 못 차렸네. 사고 쳐놓고 수습은 우리보고 하라는 거야?","JPN":"まだ反省してないんだね。やらかしておいて、後始末は私たちにやれってこと？","ENG":"You still don't get it, do you? So you want us to mop up your mess?","TWN":"你還沒搞清楚狀況呢！禍是你們闖的，還想要我們幫忙擦屁股嗎？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"사고도 수습도 우리가 한다는 거지. 그래서 훈련도 열심히 받고 있고.","JPN":"やらかすのも、後始末も私たちでやるってことだよ。だから一生懸命訓練も受けてるんだし。","ENG":"I'm just saying we can do both. Isn't that why we're here getting training?","TWN":"我們闖的禍我們自己負責，所以才那麼認真接受訓練。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"조심해. 이번에도 작전 무시하고 너희끼리 가면 지원이고 뭐고 없어.","JPN":"気をつけなさいね。また作戦を無視してあんたたちだけで行ったら、支援も何もないんだから。","ENG":"Careful now. If you ignore the operation again and go AWOL, there will be no backup, understand?","TWN":"小心點！這次再給我無視作戰計畫，擅自行動的話，就別妄想會有支援！"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"……지원이 없어도 또 몰래 갈 걸요? 아마도.","JPN":"……支援がなくてもまたこっそり行くと思いますよ。多分。","ENG":"B-but I think we'll still sneak out even if we don't get any backup...","TWN":"……就算沒有支援，我們還是會擅自行動，應該吧？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으음. 아마도.","JPN":"ううむ。多分。","ENG":"Hmm... Maybe.","TWN":"嗯嗯，應該吧？"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그렇지, 아마도.","JPN":"そうだね、多分。","ENG":"Yeah. Maybe.","TWN":"對啊，應該吧？"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"……그래서 지금 너네 데리고 작전 짜는 거잖아. 아예 눈앞에 두고 진행하려고.","JPN":"……だから今あんたたち込みで作戦立ててるの。最初から見えるところにおいて進めるために。","ENG":"That's why we're bringing you into this operation, aren't we? So you don't have to sneak around.","TWN":"……所以我才抓著你們一起擬定作戰計畫，直接盯著你們！"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"사실 관리국 지원을 받기엔…… 짊어져야 할 리스크가 너무 커.","JPN":"実は管理局に支援を要請するには……リスクが高すぎてね。","ENG":"But in truth, it's a big risk... to receive backup from the Administration.","TWN":"其實接受管理局的支援……需要擔負的風險有點大。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"관리국에서 헤이븐 조직을 주시하면서도, 쉽게 나서지 못한 이유가 있지.","JPN":"管理局がヘイブンの組織を注視しながらも、容易く踏み切れなかったのにも理由があるのよ。","ENG":"There's a reason why the Administration keeps an eye on Haven's organization but is hesitant to intervene.","TWN":"雖然管理局有在注意天堂組織，但他們有無法輕易出面的理由。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"이거 어쩐다. 메이드장한테라도 말해야 하나…….","JPN":"どうしよう。メイド長にでも相談すべきかな……","ENG":"I dunno... Should I ask the Chief Maid...?","TWN":"怎麼辦呢？要跟女僕長說嗎……"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아. 도움 요청할 곳이 있긴 해.","JPN":"あ。助けを要請できるところならあるよ。","ENG":"Oh. There is one place we can call for help.","TWN":"我知道可以找誰幫忙。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"설마 또 거기?","JPN":"まさか、またあそこ？","ENG":"Oh geez. Not them again...","TWN":"該不會又是那個？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};